    defaultHallCostPence: number;
    /** Maximum number of trophies to display individually in a player's trophy
     * section before resorting to a count. */
    trophyDisplayThreshold: number;
    /** Number of rows shown in a records table before the rest are hidden
     * behind a "show more" toggle. */
    recordsTableVisibleRows: number;
    /** Number of rows shown in the turnout-by-year table before older years
     * are hidden behind a "show more" toggle. */
    turnoutTableVisibleRows: number;
}

export const ConfigSchema: z.ZodType<ConfigType> = z.object({
    minGamesForAveragesTable: z.number().int().nonnegative(),
    minRepliesForSpeedyTable: z.number().int().nonnegative(),
    contactEmailDestination: z.email(),
    sessionRevalidate: z.number().int().nonnegative(),
    notificationAutoClose: z.number().int().nonnegative(),
    notificationIconSize: z.number().int().nonnegative(),
    organiserPhoneNumber: z.string().min(1),
    defaultGameCostPence: z.number().int().min(1),
    defaultHallCostPence: z.number().int().min(1),
    trophyDisplayThreshold: z.number().int().min(1),
    recordsTableVisibleRows: z.number().int().min(1),
});

import { ConfigSchema, ConfigType } from '@/types/config';

const rawConfig: ConfigType = {
    minGamesForAveragesTable: 10,
    minRepliesForSpeedyTable: 10,
    contactEmailDestination: 'footy@toastboy.co.uk',
    sessionRevalidate: 60000,
    notificationAutoClose: 4000,
    notificationIconSize: 18,
    organiserPhoneNumber: '07802 346128',
    defaultGameCostPence: 500,
    defaultHallCostPence: 4700,
    trophyDisplayThreshold: 5,
    recordsTableVisibleRows: 15,
};

// App-wide configuration object which is runtime-validated using zod. If this
// throws it will surface early during server start / build so misconfiguration
// is caught quickly.

export const config = ConfigSchema.parse(rawConfig);

