    it('calls outcomeService.getTurnoutByYear', async () => {
        await TurnoutPage();

        expect(outcomeService.getTurnoutByYear).toHaveBeenCalledTimes(1);
    });

    it('passes the turnout data to the Turnout component', async () => {
        const turnout = [{ year: 2021, count: 10 }];
